[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ClearCache,[switch]$RepairWebView2,[switch]$ResetTeamsPackage,[switch]$RestartAudio,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\TeamsClientRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ClearCache-or$RepairWebView2-or$ResetTeamsPackage-or$RestartAudio)){throw'Choose at least one repair action.'}
Get-AppxPackage MSTeams -ErrorAction SilentlyContinue|Export-Clixml (Join-Path $OutputPath 'teams-before.xml')
if($ClearCache){$p=Get-Process ms-teams,Teams -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Teams or use -Force.'};if($p){$p|Stop-Process -Force};foreach($x in @("$env:APPDATA\Microsoft\Teams","$env:LOCALAPPDATA\Packages\MSTeams_8wekyb3d8bbwe\LocalCache\Microsoft\MSTeams")){if(Test-Path $x){if($PSCmdlet.ShouldProcess($x,'Clear Teams cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Teams cache cleared.'}
if($RepairWebView2){$setup=Get-ChildItem "$env:ProgramFiles(x86)\Microsoft\EdgeWebView\Application" -Filter setup.exe -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName;if(-not$setup){throw'WebView2 setup not found.'};if($PSCmdlet.ShouldProcess('WebView2 Runtime','Repair')){Start-Process $setup '--repair --force-uninstall --msedgewebview --system-level' -Wait;L'WebView2 repair completed.'}}
if($ResetTeamsPackage){$pkg=Get-AppxPackage MSTeams -ErrorAction Stop;if($PSCmdlet.ShouldProcess($pkg.PackageFullName,'Reset app package')){Reset-AppxPackage -Package $pkg.PackageFullName;L'Teams package reset.'}}
if($RestartAudio-and$PSCmdlet.ShouldProcess('Windows Audio services','Restart')){Restart-Service AudioEndpointBuilder -Force;Restart-Service Audiosrv -Force;L'Audio services restarted.'}
L'Repair workflow finished.'